// Memory Telegram bot handler.
// Routes /memory_* commands, queries memory_runs and Qdrant, builds a plaintext
// reply. Plaintext is deliberate: no Markdown/HTML parsing to avoid the escaping
// traps that bit us on the alert workflows.
const { Client } = require('pg');
const http = require('http');

const data = $input.first().json;
const body = data.body || {};
const message = body.message || {};
const chat = message.chat || {};
const chatId = chat.id;
const text = (message.text || '').trim();

const allowedChatId = $env.TELEGRAM_MONITORING_CHAT_ID;

// Silent drop: unknown chat, don't even reply — keeps the bot quiet for
// anyone who found the URL without the secret (defence in depth on top of
// the setWebhook secret_token check).
if (!chatId || String(chatId) !== String(allowedChatId)) {
  return [{ json: { skip: true, reason: 'unauthorized_chat', chat_id: chatId } }];
}

// Normalize the command (strip @BotName suffix if present, lowercase).
let cmd = text.split(/\s+/)[0] || '';
cmd = cmd.split('@')[0].toLowerCase();

function fmtAge(hours) {
  if (hours == null) return 'n/a';
  const h = Number(hours);
  if (h < 1) return `${Math.round(h * 60)}min`;
  if (h < 48) return `${h.toFixed(1)}h`;
  return `${Math.round(h / 24)}d`;
}

function checkQdrant() {
  return new Promise((resolve) => {
    const req = http.request(
      {
        hostname: 'javisi_qdrant',
        port: 6333,
        path: '/collections/memory_v1',
        method: 'GET',
        timeout: 4000,
        headers: { 'api-key': $env.QDRANT_API_KEY || '' }
      },
      (res) => {
        let d = '';
        res.on('data', (c) => d += c);
        res.on('end', () => {
          if (res.statusCode === 401 || res.statusCode === 403) {
            resolve({ reachable: false, error: `auth_${res.statusCode}` });
            return;
          }
          try {
            const parsed = JSON.parse(d);
            const r = parsed.result || {};
            resolve({
              reachable: res.statusCode === 200,
              status: r.status || null,
              points: r.points_count ?? null,
              vectors: r.vectors_count ?? null
            });
          } catch (e) {
            resolve({ reachable: false, error: 'parse_error' });
          }
        });
      }
    );
    req.on('error', (e) => resolve({ reachable: false, error: e.message }));
    req.on('timeout', () => {
      req.destroy();
      resolve({ reachable: false, error: 'timeout' });
    });
    req.end();
  });
}

async function queryLastRun() {
  const client = new Client({
    host: 'postgresql',
    port: 5432,
    database: 'n8n',
    user: 'n8n',
    password: $env.DB_POSTGRESDB_PASSWORD
  });
  await client.connect();
  try {
    const r = await client.query(`
      SELECT run_id, host_origin, mode, exit_code, attempted_files,
             indexed_files, indexed_chunks, spool_size, qdrant_reachable,
             loadavg_1min, duration_sec, received_at,
             EXTRACT(EPOCH FROM (NOW() - received_at)) / 3600.0 AS age_hours,
             errors::text AS errors_text
      FROM memory_runs
      ORDER BY received_at DESC
      LIMIT 1
    `);
    return r.rows[0] || null;
  } finally {
    await client.end();
  }
}

async function queryLastRuns(limit) {
  const client = new Client({
    host: 'postgresql',
    port: 5432,
    database: 'n8n',
    user: 'n8n',
    password: $env.DB_POSTGRESDB_PASSWORD
  });
  await client.connect();
  try {
    const r = await client.query(`
      SELECT run_id, mode, exit_code, indexed_files, indexed_chunks,
             spool_size, loadavg_1min, received_at,
             EXTRACT(EPOCH FROM (NOW() - received_at)) / 3600.0 AS age_hours
      FROM memory_runs
      ORDER BY received_at DESC
      LIMIT $1
    `, [limit]);
    return r.rows;
  } finally {
    await client.end();
  }
}

// Read the single-row-per-host live state table. One row per worker host;
// today we only have Waza but the query is host-agnostic so adding more
// workers later just works. Fresh start events overwrite the row via UPSERT.
async function queryWorkerStates() {
  const client = new Client({
    host: 'postgresql',
    port: 5432,
    database: 'n8n',
    user: 'n8n',
    password: $env.DB_POSTGRESDB_PASSWORD
  });
  await client.connect();
  try {
    const r = await client.query(`
      SELECT host_origin, state, started_at, mode, repos_target,
             last_run_id, last_exit_code, last_completed_at, updated_at,
             EXTRACT(EPOCH FROM (NOW() - started_at)) / 60.0 AS running_minutes
      FROM memory_worker_state
      ORDER BY host_origin
    `);
    return r.rows;
  } catch (e) {
    // Table may not exist on first deploy — fall back to empty state so
    // /memory_status still works instead of crashing the bot.
    if (e.code === '42P01') return [];
    throw e;
  } finally {
    await client.end();
  }
}

function workerStateLines(states) {
  if (!states || states.length === 0) {
    return ['Worker live state: unknown (no state row yet — waiting for first start event)'];
  }
  const lines = [];
  for (const s of states) {
    const host = s.host_origin || '?';
    if (s.state === 'running') {
      const mins = s.running_minutes != null ? `${Math.round(Number(s.running_minutes))}min` : '?';
      const repos = Array.isArray(s.repos_target) ? s.repos_target.join(', ') : (s.repos_target || 'all');
      lines.push(`Worker (${host}): RUNNING — started ${mins} ago, mode=${s.mode || '?'}`);
      lines.push(`  targets: ${repos}`);
    } else {
      lines.push(`Worker (${host}): idle`);
    }
  }
  return lines;
}

// Helper: render a clear Qdrant line distinguishing service state from
// the bot's ability to reach it. "DOWN" is never printed for an auth error
// because auth errors mean Qdrant is answering, we just don't have a key.
function qdrantLine(q) {
  if (q.reachable) {
    const pts = q.points != null ? `${q.points} points indexed` : 'points: n/a';
    return `Qdrant vector DB: UP (${pts})`;
  }
  if (q.error && q.error.startsWith('auth_')) {
    return `Qdrant vector DB: reachable but bot has no API key (${q.error})`;
  }
  return `Qdrant vector DB: UNREACHABLE from bot (${q.error || q.status || 'unknown'})`;
}

let reply;

try {
  if (cmd === '/memory_status') {
    const [qdrant, lastRun, workerStates] = await Promise.all([
      checkQdrant(),
      queryLastRun(),
      queryWorkerStates()
    ]);
    const lines = ['Memory pipeline — status', ''];
    lines.push(qdrantLine(qdrant));
    lines.push('');
    for (const l of workerStateLines(workerStates)) lines.push(l);
    lines.push('');
    if (!lastRun) {
      lines.push('Last worker run: NONE recorded yet.');
      lines.push('(Waza has never posted a run report to n8n.)');
    } else {
      const okMark = lastRun.exit_code === 0 ? 'success' : `FAILED (exit ${lastRun.exit_code})`;
      lines.push(`Last worker run: ${fmtAge(lastRun.age_hours)} ago — ${okMark}`);
      lines.push(`  host: ${lastRun.host_origin || '?'}   mode: ${lastRun.mode || '?'}`);
      lines.push(`  indexed: ${lastRun.indexed_files ?? 0}/${lastRun.attempted_files ?? 0} files, ${lastRun.indexed_chunks ?? 0} chunks`);
      const spoolNote = (lastRun.spool_size ?? 0) === 0 ? '0 (empty)' : `${lastRun.spool_size} (pending)`;
      lines.push(`  spool backlog: ${spoolNote}   load avg: ${lastRun.loadavg_1min ?? '?'}`);
      if (lastRun.duration_sec != null) {
        lines.push(`  run duration: ${Number(lastRun.duration_sec).toFixed(0)}s`);
      }
      if (lastRun.qdrant_reachable === false) {
        lines.push('  NOTE: Qdrant was unreachable DURING that run (worker side)');
      }
      if (lastRun.errors_text && lastRun.errors_text !== '[]') {
        lines.push(`  errors: ${lastRun.errors_text.slice(0, 180)}`);
      }
      lines.push(`  run_id: ${lastRun.run_id}`);
    }
    lines.push('');
    lines.push('Pipeline is push-only: this shows the last report Waza sent.');
    lines.push('Use /memory_health for a pass/fail verdict against thresholds.');
    reply = lines.join('\n');
  } else if (cmd === '/memory_last') {
    const rows = await queryLastRuns(5);
    if (rows.length === 0) {
      reply = 'Memory pipeline — last runs\n\nNo run reports recorded yet.';
    } else {
      const lines = ['Memory pipeline — last 5 worker runs', ''];
      lines.push('(newest first; each line = one run report from Waza)');
      lines.push('');
      for (const r of rows) {
        const mark = r.exit_code === 0 ? 'OK ' : 'ERR';
        lines.push(`${mark}  ${fmtAge(r.age_hours).padEnd(6)}  ${r.mode || '?'}  files=${r.indexed_files ?? 0}  chunks=${r.indexed_chunks ?? 0}  spool=${r.spool_size ?? '?'}  load=${r.loadavg_1min ?? '?'}`);
      }
      reply = lines.join('\n');
    }
  } else if (cmd === '/memory_health') {
    const maxAge = Number($env.MEMORY_HEALTHCHECK_MAX_AGE_HOURS || '2');
    const maxSpool = Number($env.MEMORY_HEALTHCHECK_MAX_SPOOL || '50');
    const [qdrant, lastRun] = await Promise.all([checkQdrant(), queryLastRun()]);
    const issues = [];
    // Only count Qdrant as unhealthy if it truly can't be reached, not
    // if we just lack an API key (that's a bot-config issue, not a prod outage).
    if (!qdrant.reachable && !(qdrant.error && qdrant.error.startsWith('auth_'))) {
      issues.push(`qdrant_unreachable:${qdrant.error || qdrant.status}`);
    }
    if (!lastRun) {
      issues.push('no_runs_recorded');
    } else {
      const h = Number(lastRun.age_hours || 0);
      if (h > maxAge) issues.push(`stale_last_run:${h.toFixed(1)}h_ago`);
      if ((lastRun.spool_size ?? 0) > maxSpool) issues.push(`spool_high:${lastRun.spool_size}`);
      if (lastRun.qdrant_reachable === false) issues.push('worker_saw_qdrant_unreachable');
      if (lastRun.exit_code !== 0) issues.push(`last_run_exit_code:${lastRun.exit_code}`);
    }
    const lines = ['Memory pipeline — on-demand healthcheck', ''];
    if (issues.length === 0) {
      lines.push('Verdict: HEALTHY');
      lines.push('');
      lines.push(qdrantLine(qdrant));
      if (lastRun) lines.push(`Last run: ${fmtAge(lastRun.age_hours)} ago, exit=${lastRun.exit_code}`);
    } else {
      lines.push('Verdict: UNHEALTHY');
      lines.push('');
      lines.push('Issues detected:');
      for (const i of issues) lines.push(`  - ${i}`);
      lines.push('');
      lines.push(qdrantLine(qdrant));
    }
    lines.push('');
    lines.push(`Thresholds: max_age=${maxAge}h, max_spool=${maxSpool} files`);
    reply = lines.join('\n');
  } else if (cmd === '/memory_help' || cmd === '/help' || cmd === '/start') {
    reply = [
      'Memory pipeline bot',
      '',
      'Available commands:',
      '',
      '/memory_status  — last worker run + live Qdrant state',
      '/memory_last    — last 5 worker runs (compact list)',
      '/memory_health  — pass/fail verdict vs thresholds',
      '/memory_help    — this help message',
      '',
      'The pipeline is push-only: the worker on Waza posts a JSON report',
      'to n8n after every run. This bot only reads the memory_runs table',
      'and Qdrant directly — it never SSHes into Waza.'
    ].join('\n');
  } else {
    // Unknown command or non-command message — silent to avoid chatter.
    return [{ json: { skip: true, reason: 'unknown_command', text } }];
  }
} catch (err) {
  reply = `Memory bot error\n\n${err.message || 'unknown error'}`;
}

return [{
  json: {
    skip: false,
    chat_id: chatId,
    reply_text: reply
  }
}];
